html.light body {
  background:
    radial-gradient(
      ellipse 1200px 600px at 80% -10%,
      rgba(234, 88, 12, 0.07),
      transparent 60%
    ),
    radial-gradient(
      ellipse 800px 500px at 0% 100%,
      rgba(234, 88, 12, 0.04),
      transparent 60%
    ),
    var(--color-bg);
}

html.light body::before {
  display: none;
}

body {
  background:
    radial-gradient(
      ellipse 1200px 600px at 80% -10%,
      rgba(249, 115, 22, 0.05),
      transparent 60%
    ),
    radial-gradient(
      ellipse 800px 500px at 0% 100%,
      rgba(249, 115, 22, 0.03),
      transparent 60%
    ),
    var(--color-bg);
  color: var(--color-fg);
  font-family: var(--font-sans);
  font-feature-settings: "cv11", "ss01", "ss03";
  font-weight: 500;
  letter-spacing: 0;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

