import { Activity, Building2, Command, MessageSquare, Moon, PanelLeft, Play, Settings, Sun, Sparkles } from "lucide-react";
import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { cn } from "../lib/cn";

type Props = {
  onOpenPalette: () => void;
  onOpenMcpSettings: () => void;
  askEnabled?: boolean;
  askActive: boolean;
  onToggleAsk: () => void;
  treeActive: boolean;
  onToggleTree: () => void;
};

export function TopBar({
  onOpenPalette,
  onOpenMcpSettings,
  askEnabled = true,
  askActive,
  onToggleAsk,
  treeActive,
  onToggleTree,
}: Props) {
  const params = useParams();
  const lie = params.lie ?? "";
  const [theme, setTheme] = useState<"dark" | "light">(() => {
    if (typeof window === "undefined") return "dark";
    const stored = window.localStorage.getItem("theme");
    if (stored === "light" || stored === "dark") return stored;
    return window.matchMedia("(prefers-color-scheme: light)").matches ? "light" : "dark";
  });

  useEffect(() => {
    const root = document.documentElement;
    root.classList.toggle("dark", theme === "dark");
    root.classList.toggle("light", theme === "light");
    window.localStorage.setItem("theme", theme);
  }, [theme]);

  return (
    <header className="glass sticky top-0 z-40 flex h-12 items-center justify-between gap-4 border-b border-[var(--color-border)] px-4">
      <div className="flex items-center gap-3">
        <button
          onClick={onToggleTree}
          aria-label={treeActive ? "Close Tree panel" : "Open Tree panel"}
          title={treeActive ? "Close Tree panel" : "Open Tree panel"}
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border transition-colors",
            treeActive
              ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
              : "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)] hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          <PanelLeft className="h-3.5 w-3.5" />
        </button>
        <div className="flex items-center gap-2">
          <div className="grid h-6 w-6 place-items-center rounded-md bg-[var(--color-accent)] text-[#0b0b0a]">
            <Building2 className="h-3.5 w-3.5" strokeWidth={2.5} />
          </div>
          <span className="font-display text-[16px] font-medium tracking-tight text-[var(--color-ink-50)]">
            PropContext
          </span>
        </div>
      </div>

      <div className="flex items-center gap-2">
        <button
          onClick={onOpenPalette}
          className={cn(
            "group flex h-7 shrink-0 items-center gap-2 whitespace-nowrap rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] px-2.5 text-[16px] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          <Sparkles className="h-3 w-3 shrink-0 text-[var(--color-accent)]" />
          <span className="hidden sm:inline">Jump to file</span>
          <kbd className="ml-1 hidden items-center gap-0.5 rounded border border-[var(--color-border)] bg-[var(--color-bg)] px-1 py-0 font-mono text-[10px] tracking-tight text-[var(--color-fg-dim)] sm:flex">
            <Command className="h-2.5 w-2.5" />K
          </kbd>
        </button>

        {askEnabled && (
          <button
            onClick={onToggleAsk}
            aria-label={askActive ? "Close Ask panel" : "Open Ask panel"}
            title={askActive ? "Close Ask panel" : "Open Ask panel"}
            className={cn(
              "grid h-7 w-7 place-items-center rounded-md border transition-colors",
              askActive
                ? "border-[var(--color-accent-dim)] bg-[var(--color-surface)] text-[var(--color-accent)]"
                : "border-[var(--color-border-2)] bg-[var(--color-surface)] text-[var(--color-fg-muted)] hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
            )}
          >
            <MessageSquare className="h-3.5 w-3.5" />
          </button>
        )}

        <a
          href="/ingest"
          aria-label="Simulate ingest"
          title="Simulate ingest"
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          <Play className="h-3.5 w-3.5" />
        </a>

        <a
          href={lie ? `/p/${lie}/hermes` : "/hermes"}
          aria-label="Hermes dashboard"
          title="Hermes — self-improvement loop"
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          <Activity className="h-3.5 w-3.5" />
        </a>

        <button
          onClick={onOpenMcpSettings}
          aria-label="MCP connection settings"
          title="Connect via MCP"
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          <Settings className="h-3.5 w-3.5" />
        </button>

        <button
          onClick={() => setTheme((t) => (t === "dark" ? "light" : "dark"))}
          aria-label="Toggle theme"
          className={cn(
            "grid h-7 w-7 place-items-center rounded-md border border-[var(--color-border-2)]",
            "bg-[var(--color-surface)] text-[var(--color-fg-muted)]",
            "transition-colors hover:border-[var(--color-accent-dim)] hover:text-[var(--color-fg)]",
          )}
        >
          {theme === "dark" ? (
            <Sun className="h-3.5 w-3.5" />
          ) : (
            <Moon className="h-3.5 w-3.5" />
          )}
        </button>
      </div>
    </header>
  );
}

import { useEffect, useState } from "react";
import { ChevronRight, FileText, Folder, FolderOpen } from "lucide-react";
import type { TreeNode } from "../api";
import { cn } from "../lib/cn";

type Props = {
  node: TreeNode;
  selectedPath: string | null;
  onSelect: (path: string) => void;
  depth?: number;
  isRoot?: boolean;
};

export function Tree({ node, selectedPath, onSelect, depth = 0, isRoot }: Props) {
  const [open, setOpen] = useState(depth < 2);

  useEffect(() => {
    if (selectedPath && node.type === "dir" && selectedPath.startsWith(node.path + "/")) {
      setOpen(true);
    }
  }, [selectedPath, node]);

  if (node.type === "file") {
    const active = node.path === selectedPath;
    const displayName = node.name.replace(/\.md$/, "");
    return (
      <button
        type="button"
        onClick={() => onSelect(node.path)}
        className={cn(
          "group relative flex w-full items-center gap-2 rounded-md py-[3px] pr-2 text-left transition-colors",
          "font-mono text-[16px]",
          active
            ? "bg-[var(--color-surface-2)] text-[var(--color-accent)]"
            : "text-[var(--color-fg-muted)] hover:bg-[var(--color-surface)] hover:text-[var(--color-fg)]",
        )}
        style={{ paddingLeft: 8 + depth * 14 }}
      >
        {active && (
          <span className="absolute left-0 top-1/2 h-4 w-[2px] -translate-y-1/2 rounded-r bg-[var(--color-accent)]" />
        )}
        <FileText
          className={cn(
            "h-3.5 w-3.5 shrink-0",
            active ? "text-[var(--color-accent)]" : "text-[var(--color-fg-dim)]",
          )}
        />
        <span className="truncate">{displayName}</span>
      </button>
    );
  }

  const children = node.children ?? [];
  const label = isRoot ? node.name : node.name;

  return (
    <div className="select-none">
      <button
        type="button"
        onClick={() => setOpen((o) => !o)}
        className={cn(
          "group flex w-full items-center gap-1.5 rounded-md py-[3px] pr-2 text-left transition-colors",
          "font-mono text-[16px] text-[var(--color-ink-100)]",
          "hover:bg-[var(--color-surface)]",
        )}
        style={{ paddingLeft: 8 + depth * 14 }}
      >
        <ChevronRight
          className={cn(
            "h-3 w-3 shrink-0 text-[var(--color-fg-dim)] transition-transform duration-150",
            open && "rotate-90",
          )}
          strokeWidth={2.4}
        />
        {open ? (
          <FolderOpen
            className={cn(
              "h-3.5 w-3.5 shrink-0",
              isRoot ? "text-[var(--color-accent)]" : "text-[var(--color-fg-muted)]",
            )}
            strokeWidth={1.8}
          />
        ) : (
          <Folder
            className={cn(
              "h-3.5 w-3.5 shrink-0",
              isRoot ? "text-[var(--color-accent)]" : "text-[var(--color-fg-muted)]",
            )}
            strokeWidth={1.8}
          />
        )}
        <span className={cn("truncate", isRoot && "font-medium tracking-tight")}>
          {label}
        </span>
      </button>
      {open && children.length > 0 && (
        <div className="relative fade-up">
          {depth >= 0 && (
            <span
              className="absolute top-0 bottom-1 w-px bg-[var(--color-border)]"
              style={{ left: 8 + depth * 14 + 5 }}
              aria-hidden
            />
          )}
          {children.map((c) => (
            <Tree
              key={c.path}
              node={c}
              selectedPath={selectedPath}
              onSelect={onSelect}
              depth={depth + 1}
            />
          ))}
        </div>
      )}
    </div>
  );
}
